#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
ll n,m,ans=0;
multiset<ll> x;
int main(void)
{
    n=read(),m=read();
    for(ll i=1,a;i<=n;++i){
        a=read();
        a*=i;
        if(a)x.insert(a);
    }
    for(ll i=1,b;i<=m;++i){
        b=read();
        b*=i;
        ans+=x.count(b);
    }
    write(ans);
	return false;
}
